<div class="two-column-layout"><section class="panel"><div class="panel-header"><div><h3><?=$editing?'Editar categoría':'Nueva categoría'?></h3><p>Complete los datos obligatorios.</p></div></div><form method="post" action="index.php?route=categorias/guardar" class="form-grid"><input type="hidden" name="csrf_token" value="<?=App\Helpers\Csrf::token()?>"><input type="hidden" name="id" value="<?=$editing['IdCategoria']??0?>"><label>Código<input class="form-control" name="codigo" maxlength="30" required value="<?=htmlspecialchars($editing['Codigo']??'')?>"></label><label>Nombre<input class="form-control" name="nombre" maxlength="100" required value="<?=htmlspecialchars($editing['Nombre']??'')?>"></label><label class="full">Descripción<textarea class="form-control" name="descripcion" rows="3"><?=htmlspecialchars($editing['Descripcion']??'')?></textarea></label><label>Estado<select class="form-select" name="estado"><option value="1" <?=($editing['Estado']??1)?'selected':''?>>Activo</option><option value="0" <?=isset($editing['Estado'])&&!$editing['Estado']?'selected':''?>>Inactivo</option></select></label><div class="full d-flex gap-2"><button class="btn btn-primary"><i class="bi bi-check2-circle me-2"></i>Guardar</button><?php if($editing):?><a class="btn btn-light" href="index.php?route=categorias">Cancelar</a><?php endif;?></div></form></section>
